def solve(weight: list[int]) -> int:
    n = len(weight)
    if n < 2:
        return 0

    res = 0
    i = 0
    while i < n:
        max_val = weight[i]
        last = i
        # Find the largest possible segment starting at i
        for j in range(i + 1, n):
            if weight[j] > max_val:
                max_val = weight[j]
            # Check if current segment is balanced
            if weight[j] < max_val:
                last = j
        # If we found a valid segment
        if last > i:
            res += 1
            i = last + 1
        else:
            i += 1
    return res
